1	#!/usr/bin/env node
2	/**
3	 * GSD-T Dashboard Server — Zero-dep SSE server for .gsd-t/events/*.jsonl
4	 * Serves gsd-t-dashboard.html and streams events to browser clients.
5	 */
6	const http = require("http");
7	const fs = require("fs");
8	const path = require("path");
9	const { spawn } = require("child_process");
10	
11	// Base port — the effective default is project-hashed (see
12	// projectScopedDefaultPort). Explicit --port N always overrides.
13	const DEFAULT_PORT = 7433;
14	const MAX_EVENTS = 500;
15	
16	/**
17	 * Deterministic project-scoped default port so two projects running
18	 * `gsd-t visualize` simultaneously don't collide on 7433. Hashes the
19	 * resolved project directory (djb2) and maps into [7433, 7532].
20	 *
21	 * @param {string} projectDir — any path-like string; resolved internally.
22	 * @returns {number} port in [DEFAULT_PORT, DEFAULT_PORT + 99].
23	 */
24	function projectScopedDefaultPort(projectDir) {
25	  const resolved = path.resolve(projectDir || ".");
26	  let hash = 5381;
27	  for (let i = 0; i < resolved.length; i++) {
28	    hash = ((hash * 33) ^ resolved.charCodeAt(i)) >>> 0;
29	  }
30	  return DEFAULT_PORT + (hash % 100);
31	}
32	
33	/**
34	 * Pure helper so callers (and tests) can resolve the effective port from a
35	 * parsed --port argument + projectDir. Explicit argPort always wins.
36	 */
37	function resolvePort({ argPort, projectDir }) {
38	  if (argPort != null && argPort !== "" && !Number.isNaN(parseInt(argPort, 10))) {
39	    return parseInt(argPort, 10);
40	  }
41	  return projectScopedDefaultPort(projectDir);
42	}
43	const KEEPALIVE_MS = 15000;
44	const SSE_HEADERS = { "Content-Type": "text/event-stream", "Cache-Control": "no-cache", "Connection": "keep-alive", "Access-Control-Allow-Origin": "*" };
45	
46	function parseEventLine(line) {
47	  if (!line || !line.trim()) return null;
48	  try { return JSON.parse(line.trim()); } catch { return null; }
49	}
50	
51	function findEventsDir(projectDir) {
52	  return path.join(projectDir || process.cwd(), ".gsd-t", "events");
53	}
54	
55	function safeReadJsonl(filePath) {
56	  try { if (fs.lstatSync(filePath).isSymbolicLink()) return []; } catch { /* safe */ }
57	  try { return fs.readFileSync(filePath, "utf8").split("\n").map(parseEventLine).filter(Boolean); } catch { return []; }
58	}
59	
60	function readExistingEvents(eventsDir, maxEvents) {
61	  const limit = maxEvents || MAX_EVENTS;
62	  if (!eventsDir) return [];
63	  try { fs.accessSync(eventsDir); } catch { return []; }
64	  let files;
65	  try { files = fs.readdirSync(eventsDir).filter((f) => f.endsWith(".jsonl")).sort().reverse(); } catch { return []; }
66	  const results = [];
67	  for (const f of files) {
68	    if (results.length >= limit) break;
69	    safeReadJsonl(path.join(eventsDir, f)).forEach((e) => { if (results.length < limit) results.push(e); });
70	  }
71	  return results;
72	}
73	
74	function tailEventsFile(filePath, callback) {
75	  let offset = 0;
76	  try { offset = fs.statSync(filePath).size; } catch { /* new file */ }
77	  function processNewData() {
78	    try { if (fs.lstatSync(filePath).isSymbolicLink()) return; } catch { return; }
79	    let stat;
80	    try { stat = fs.statSync(filePath); } catch { return; }
81	    if (stat.size <= offset) return;
82	    const fd = fs.openSync(filePath, "r");
83	    let chunk;
84	    try {
85	      const buf = Buffer.alloc(stat.size - offset);
86	      fs.readSync(fd, buf, 0, buf.length, offset);
87	      chunk = buf.toString("utf8");
88	      offset = stat.size;
89	    } finally { fs.closeSync(fd); }
90	    chunk.split("\n").forEach((line) => { const obj = parseEventLine(line); if (obj) callback(obj); });
91	  }
92	  fs.watchFile(filePath, { interval: 500, persistent: true }, processNewData);
93	  return () => fs.unwatchFile(filePath, processNewData);
94	}
95	
96	function handleRoot(req, res, htmlPath) {
97	  fs.readFile(htmlPath, (err, data) => {
98	    if (err) { res.writeHead(404); res.end("Not found"); return; }
99	    res.writeHead(200, { "Content-Type": "text/html" });
100	    res.end(data);
101	  });
102	}
103	
104	function handlePing(req, res, port) {
105	  res.writeHead(200, { "Content-Type": "application/json" });
106	  res.end(JSON.stringify({ status: "ok", port }));
107	}
108	
109	function handleStop(req, res, server) {
110	  res.writeHead(200, { "Content-Type": "application/json" });
111	  res.end(JSON.stringify({ status: "stopping" }));
112	  setImmediate(() => server.close());
113	}
114	
115	function getNewestJsonl(eventsDir) {
116	  try { const files = fs.readdirSync(eventsDir).filter((f) => f.endsWith(".jsonl")).sort(); return files.length ? path.join(eventsDir, files[files.length - 1]) : null; } catch { return null; }
117	}
118	
119	function handleEvents(req, res, eventsDir) {
120	  res.writeHead(200, SSE_HEADERS);
121	  readExistingEvents(eventsDir, MAX_EVENTS).forEach((e) => { try { res.write("data: " + JSON.stringify(e) + "\n\n"); } catch { /* gone */ } });
122	  const sendEvent = (obj) => { try { res.write("data: " + JSON.stringify(obj) + "\n\n"); } catch { /* gone */ } };
123	  let watchedFile = getNewestJsonl(eventsDir);
124	  let unwatchFile = watchedFile ? tailEventsFile(watchedFile, sendEvent) : null;
125	  // Watch events directory for new JSONL files (e.g., after midnight date rollover)
126	  let dirWatcher = null;
127	  try {
128	    dirWatcher = fs.watch(eventsDir, (eventType, filename) => {
129	      if (!filename || !filename.endsWith(".jsonl")) return;
130	      const newFile = getNewestJsonl(eventsDir);
131	      if (newFile && newFile !== watchedFile) {
132	        if (unwatchFile) unwatchFile();
133	        watchedFile = newFile;
134	        unwatchFile = tailEventsFile(watchedFile, sendEvent);
135	      }
136	    });
137	  } catch { /* eventsDir may not exist yet */ }
138	  const timer = setInterval(() => { try { res.write(": keepalive\n\n"); } catch { clearInterval(timer); } }, KEEPALIVE_MS);
139	  req.on("close", () => { clearInterval(timer); if (unwatchFile) unwatchFile(); if (dirWatcher) dirWatcher.close(); });
140	}
141	
142	function readMetricsData(metricsDir) {
143	  const taskFile = path.join(metricsDir, "task-metrics.jsonl");
144	  const rollupFile = path.join(metricsDir, "rollup.jsonl");
145	  const taskMetrics = fs.existsSync(taskFile) ? safeReadJsonl(taskFile) : [];
146	  const rollups = fs.existsSync(rollupFile) ? safeReadJsonl(rollupFile) : [];
147	  return { taskMetrics, rollups };
148	}
149	
150	function handleMetrics(req, res, projectDir) {
151	  const metricsDir = path.join(projectDir, ".gsd-t", "metrics");
152	  const data = readMetricsData(metricsDir);
153	  res.writeHead(200, { "Content-Type": "application/json" });
154	  res.end(JSON.stringify(data));
155	}
156	
157	// ── M42 D2 — per-spawn transcript routes ──────────────────────────────────────
158	
159	const TRANSCRIPTS_SUBDIR = path.join(".gsd-t", "transcripts");
160	
161	function transcriptsDir(projectDir) {
162	  return path.join(projectDir, TRANSCRIPTS_SUBDIR);
163	}
164	
165	function readTranscriptsIndex(projectDir) {
166	  const p = path.join(transcriptsDir(projectDir), ".index.json");
167	  try {
168	    const raw = fs.readFileSync(p, "utf8");
169	    const parsed = JSON.parse(raw);
170	    if (parsed && Array.isArray(parsed.spawns)) return parsed;
171	  } catch { /* no index yet */ }
172	  return { spawns: [] };
173	}
174	
175	function isValidSpawnId(id) {
176	  return typeof id === "string" && /^[a-zA-Z0-9._-]+$/.test(id) && id.length <= 200;
177	}
178	
179	function handleTranscriptsList(req, res, projectDir) {
180	  const idx = readTranscriptsIndex(projectDir);
181	  const sorted = idx.spawns
182	    .slice()
183	    .sort((a, b) => (Date.parse(b.startedAt) || 0) - (Date.parse(a.startedAt) || 0));
184	
185	  // Content negotiation: browser navigations send Accept: text/html, fetch()
186	  // defaults to */*. We serve HTML only when the client explicitly asks for it,
187	  // so the existing dashboard fetch (which expects JSON) stays unaffected.
188	  const accept = String(req.headers["accept"] || "");
189	  if (accept.includes("text/html")) {
190	    res.writeHead(200, { "Content-Type": "text/html; charset=utf-8" });
191	    res.end(renderTranscriptsHtml(sorted));
192	    return;
193	  }
194	  res.writeHead(200, { "Content-Type": "application/json" });
195	  res.end(JSON.stringify({ spawns: sorted }));
196	}
197	
198	function renderTranscriptsHtml(spawns) {
199	  const escape = (s) => String(s == null ? "" : s)
200	    .replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;")
201	    .replace(/"/g, "&quot;");
202	  const fmtDuration = (a, b) => {
203	    const start = Date.parse(a); const end = Date.parse(b || "") || Date.now();
204	    if (!Number.isFinite(start)) return "—";
205	    const ms = Math.max(0, end - start);
206	    const s = Math.floor(ms / 1000); const m = Math.floor(s / 60); const r = s % 60;
207	    return m > 0 ? `${m}m ${r}s` : `${r}s`;
208	  };
209	  const fmtTime = (s) => { const d = new Date(s); return Number.isFinite(d.getTime()) ? d.toLocaleString() : "—"; };
210	  const liveStatuses = new Set(["initializing", "running"]);
211	  const isLive = (s) => liveStatuses.has(s);
212	
213	  const rows = spawns.map((s) => {
214	    const live = isLive(s.status);
215	    const statusBadge = `<span class="status status-${escape(s.status || 'unknown')}">${escape(s.status || 'unknown')}</span>`;
216	    return `<tr class="${live ? 'row-live' : ''}">
217	      <td><a href="/transcript/${encodeURIComponent(s.spawnId)}">${escape(s.spawnId)}</a></td>
218	      <td>${escape(s.command || '—')}</td>
219	      <td>${escape(s.description || '—')}</td>
220	      <td>${statusBadge}</td>
221	      <td>${escape(fmtTime(s.startedAt))}</td>
222	      <td>${escape(fmtDuration(s.startedAt, s.endedAt))}</td>
223	    </tr>`;
224	  }).join("");
225	
226	  const empty = `<div class="empty">
227	    <h2>No spawn transcripts yet</h2>
228	    <p>Transcripts appear here as soon as the first agent spawns. Run any GSD-T command (for example <code>/gsd-t-quick</code>) to generate one.</p>
229	    <p><a href="/">← Back to dashboard</a></p>
230	  </div>`;
231	
232	  const table = spawns.length ? `<table>
233	    <thead><tr><th>Spawn ID</th><th>Command</th><th>Description</th><th>Status</th><th>Started</th><th>Duration</th></tr></thead>
234	    <tbody>${rows}</tbody>
235	  </table>` : empty;
236	
237	  return `<!DOCTYPE html>
238	<html lang="en"><head><meta charset="UTF-8"><title>GSD-T Transcripts</title>
239	<style>
240	:root{--bg:#0d1117;--surface:#161b22;--border:#30363d;--text:#e6edf3;--muted:#7d8590;
241	  --green:#3fb950;--green-bg:#1a3a1e;--blue:#388bfd;--blue-bg:#1f3a5f;--yellow:#d29922;--red:#f85149;
242	  --font:'SF Mono','Fira Code',Menlo,monospace;}
243	*{box-sizing:border-box;margin:0;padding:0}
244	body{background:var(--bg);color:var(--text);font-family:var(--font);font-size:13px;padding:20px;line-height:1.5}
245	.hdr{display:flex;align-items:center;gap:12px;margin-bottom:18px;padding-bottom:12px;border-bottom:1px solid var(--border)}
246	.logo{color:var(--blue);font-weight:bold;font-size:14px}
247	.hright{margin-left:auto;color:var(--muted);font-size:11px}
248	a{color:var(--blue);text-decoration:none}a:hover{text-decoration:underline}
249	table{width:100%;border-collapse:collapse;background:var(--surface);border:1px solid var(--border);border-radius:6px;overflow:hidden}
250	th,td{padding:8px 12px;text-align:left;border-bottom:1px solid var(--border);font-size:12px}
251	th{background:#1c2128;color:var(--muted);text-transform:uppercase;font-size:10px;letter-spacing:0.5px}
252	tbody tr:last-child td{border-bottom:none}
253	tbody tr:hover{background:#1c2128}
254	tr.row-live{background:var(--green-bg)}
255	.status{display:inline-block;padding:2px 8px;border-radius:10px;font-size:10px;text-transform:uppercase;letter-spacing:0.5px;border:1px solid}
256	.status-running,.status-initializing{background:var(--green-bg);color:var(--green);border-color:var(--green)}
257	.status-done{background:var(--blue-bg);color:var(--blue);border-color:var(--blue)}
258	.status-stopped{background:#2a2a2a;color:var(--muted);border-color:var(--border)}
259	.status-failed,.status-crashed{background:#3a1a1a;color:var(--red);border-color:var(--red)}
260	.status-unknown{color:var(--muted);border-color:var(--border)}
261	.empty{text-align:center;padding:60px 20px;color:var(--muted);background:var(--surface);border:1px solid var(--border);border-radius:6px}
262	.empty h2{color:var(--text);margin-bottom:12px;font-size:16px}
263	.empty p{margin-bottom:8px}
264	.empty code{background:#1c2128;padding:2px 6px;border-radius:3px;color:var(--green)}
265	</style></head><body>
266	<div class="hdr">
267	  <span class="logo">GSD-T Transcripts</span>
268	  <a href="/" style="font-size:11px">← Dashboard</a>
269	  <span class="hright">${spawns.length} spawn${spawns.length === 1 ? '' : 's'}</span>
270	</div>
271	${table}
272	</body></html>`;
273	}
274	
275	function handleTranscriptPage(req, res, spawnId, transcriptHtmlPath) {
276	  if (!isValidSpawnId(spawnId)) { res.writeHead(400); res.end("Invalid spawn id"); return; }
277	  fs.readFile(transcriptHtmlPath, (err, data) => {
278	    if (err) { res.writeHead(404); res.end("Transcript UI not found"); return; }
279	    // Inject the spawn-id as a data attribute on <body> by string replacement;
280	    // the HTML ships with a placeholder `data-spawn-id="__SPAWN_ID__"`.
281	    const html = data.toString("utf8").replace(/__SPAWN_ID__/g, spawnId);
282	    res.writeHead(200, { "Content-Type": "text/html" });
283	    res.end(html);
284	  });
285	}
286	
287	function tailTranscriptFile(filePath, callback) {
288	  let offset = 0;
289	  let buf = "";
290	  function processNewData() {
291	    let stat;
292	    try { stat = fs.statSync(filePath); } catch { return; }
293	    if (stat.size <= offset) return;
294	    const fd = fs.openSync(filePath, "r");
295	    try {
296	      const b = Buffer.alloc(stat.size - offset);
297	      fs.readSync(fd, b, 0, b.length, offset);
298	      buf += b.toString("utf8");
299	      offset = stat.size;
300	    } finally { fs.closeSync(fd); }
301	    let nl;
302	    while ((nl = buf.indexOf("\n")) >= 0) {
303	      const line = buf.slice(0, nl);
304	      buf = buf.slice(nl + 1);
305	      if (line.length > 0) callback(line);
306	    }
307	  }
308	  fs.watchFile(filePath, { interval: 500, persistent: true }, processNewData);
309	  return () => fs.unwatchFile(filePath, processNewData);
310	}
311	
312	// ── M43 D6 — per-spawn tool-cost + usage routes ────────────────────────────
313	
314	/**
315	 * Load per-turn usage rows for a given spawn-id from
316	 * `.gsd-t/metrics/token-usage.jsonl`.
317	 *
318	 * Rows emitted by M41/M43 include either `spawn_id` OR `session_id`. We match
319	 * against both so the route works both for headless spawns (which tag rows
320	 * with `spawn_id` at emit time) and in-session D1 captures (which tag with
321	 * the session's `session_id`).
322	 *
323	 * @param {string} projectDir
324	 * @param {string} spawnId
325	 * @returns {Array<object>}
326	 */
327	function readSpawnUsageRows(projectDir, spawnId) {
328	  const fp = path.join(projectDir, ".gsd-t", "metrics", "token-usage.jsonl");
329	  if (!fs.existsSync(fp)) return [];
330	  const lines = safeReadJsonl(fp);
331	  return lines.filter((row) => {
332	    if (!row || typeof row !== "object") return false;
333	    return row.spawn_id === spawnId || row.session_id === spawnId;
334	  });
335	}
336	
337	function handleTranscriptUsage(req, res, spawnId, projectDir) {
338	  if (!isValidSpawnId(spawnId)) { res.writeHead(400); res.end("Invalid spawn id"); return; }
339	  const rows = readSpawnUsageRows(projectDir, spawnId);
340	  res.writeHead(200, { "Content-Type": "application/json", "Access-Control-Allow-Origin": "*" });
341	  res.end(JSON.stringify({ spawn_id: spawnId, rows, generated_at: new Date().toISOString() }));
342	}
343	
344	/**
345	 * Proxy to D2's `aggregateByTool`. D2 is co-deployed in Wave 2 — if the
346	 * library isn't on disk yet, we return HTTP 503 with a machine-readable
347	 * body so the viewer panel can display "Tool attribution not yet available"
348	 * without breaking.
349	 */
350	function handleTranscriptToolCost(req, res, spawnId, projectDir) {
351	  if (!isValidSpawnId(spawnId)) { res.writeHead(400); res.end("Invalid spawn id"); return; }
352	  let attribution;
353	  try {
354	    // TODO(D6→D2): remove the try/catch once D2 lands. Keep the call shape.
355	    // eslint-disable-next-line global-require
356	    attribution = require("../bin/gsd-t-tool-attribution.cjs");
357	  } catch (_) {
358	    res.writeHead(503, { "Content-Type": "application/json", "Access-Control-Allow-Origin": "*" });
359	    res.end(JSON.stringify({ error: "tool-attribution library not yet available" }));
360	    return;
361	  }
362	  const rows = readSpawnUsageRows(projectDir, spawnId);
363	  let tools = [];
364	  try {
365	    if (typeof attribution.aggregateByTool !== "function") {
366	      res.writeHead(503, { "Content-Type": "application/json", "Access-Control-Allow-Origin": "*" });
367	      res.end(JSON.stringify({ error: "aggregateByTool not exported by tool-attribution library" }));
368	      return;
369	    }
370	    tools = attribution.aggregateByTool(rows) || [];
371	  } catch (err) {
372	    res.writeHead(500, { "Content-Type": "application/json", "Access-Control-Allow-Origin": "*" });
373	    res.end(JSON.stringify({ error: String(err && err.message ? err.message : err) }));
374	    return;
375	  }
376	  res.writeHead(200, { "Content-Type": "application/json", "Access-Control-Allow-Origin": "*" });
377	  res.end(JSON.stringify({
378	    spawn_id: spawnId,
379	    tools,
380	    generated_at: new Date().toISOString(),
381	  }));
382	}
383	
384	// ── M42 D3 — kill per-spawn ────────────────────────────────────────────────
385	
386	function writeTranscriptsIndex(projectDir, idx) {
387	  const p = path.join(transcriptsDir(projectDir), ".index.json");
388	  const tmp = p + ".tmp";
389	  try { fs.mkdirSync(path.dirname(p), { recursive: true }); } catch { /* exists */ }
390	  fs.writeFileSync(tmp, JSON.stringify(idx, null, 2));
391	  fs.renameSync(tmp, p);
392	}
393	
394	function handleTranscriptKill(req, res, spawnId, projectDir) {
395	  if (!isValidSpawnId(spawnId)) { res.writeHead(400); res.end("Invalid spawn id"); return; }
396	  const idx = readTranscriptsIndex(projectDir);
397	  const i = idx.spawns.findIndex((s) => s.spawnId === spawnId);
398	  if (i < 0) { res.writeHead(404, { "Content-Type": "application/json" }); res.end(JSON.stringify({ error: "unknown_spawn" })); return; }
399	  const entry = idx.spawns[i];
400	  const pid = entry.workerPid;
401	  if (!pid || typeof pid !== "number") {
402	    res.writeHead(409, { "Content-Type": "application/json" });
403	    res.end(JSON.stringify({ error: "no_pid_recorded" }));
404	    return;
405	  }
406	  try {
407	    process.kill(pid, "SIGTERM");
408	    idx.spawns[i].status = "stopped";
409	    idx.spawns[i].endedAt = idx.spawns[i].endedAt || new Date().toISOString();
410	    writeTranscriptsIndex(projectDir, idx);
411	    res.writeHead(200, { "Content-Type": "application/json" });
412	    res.end(JSON.stringify({ status: "stopped", pid }));
413	  } catch (err) {
414	    if (err.code === "ESRCH") {
415	      // Process already gone — treat as success and mark ended
416	      idx.spawns[i].status = idx.spawns[i].status === "running" ? "stopped" : idx.spawns[i].status;
417	      idx.spawns[i].endedAt = idx.spawns[i].endedAt || new Date().toISOString();
418	      writeTranscriptsIndex(projectDir, idx);
419	      res.writeHead(200, { "Content-Type": "application/json" });
420	      res.end(JSON.stringify({ status: "already_stopped", pid }));
421	      return;
422	    }
423	    if (err.code === "EPERM") {
424	      res.writeHead(403, { "Content-Type": "application/json" });
425	      res.end(JSON.stringify({ error: "permission_denied", pid }));
426	      return;
427	    }
428	    res.writeHead(500, { "Content-Type": "application/json" });
429	    res.end(JSON.stringify({ error: String(err.message || err) }));
430	  }
431	}
432	
433	/**
434	 * Find the transcripts-index entry for a spawn-id, or null when the index
435	 * is missing / the id isn't recorded. Used by handleTranscriptStream to
436	 * detect already-finished spawns so the SSE stream can emit `event: end`
437	 * and close instead of tailing indefinitely.
438	 */
439	function readIndexEntry(projectDir, spawnId) {
440	  const idx = readTranscriptsIndex(projectDir);
441	  if (!idx || !Array.isArray(idx.spawns)) return null;
442	  return idx.spawns.find((s) => s && s.spawnId === spawnId) || null;
443	}
444	
445	function handleTranscriptStream(req, res, spawnId, projectDir) {
446	  if (!isValidSpawnId(spawnId)) { res.writeHead(400); res.end("Invalid spawn id"); return; }
447	  const filePath = path.join(transcriptsDir(projectDir), `${spawnId}.ndjson`);
448	  let exists = true;
449	  let fileSize = 0;
450	  try { fileSize = fs.statSync(filePath).size; } catch { exists = false; }
451	
452	  res.writeHead(200, SSE_HEADERS);
453	
454	  // Consult the transcripts index — if the spawn is already finished we
455	  // replay and close instead of attaching a live tail.
456	  const entry = readIndexEntry(projectDir, spawnId);
457	  const finishedStatuses = ["done", "failed", "stopped"];
458	  const isFinished = !!(entry && entry.status && finishedStatuses.includes(entry.status));
459	
460	  // Replay: read the full file from byte 0 and send each line.
461	  let replayedBytes = 0;
462	  if (exists) {
463	    try {
464	      const full = fs.readFileSync(filePath, "utf8");
465	      replayedBytes = Buffer.byteLength(full, "utf8");
466	      full.split("\n").forEach((line) => {
467	        if (line.length > 0) {
468	          try { res.write("data: " + line + "\n\n"); } catch { /* gone */ }
469	        }
470	      });
471	    } catch { /* empty transcript */ }
472	  }
473	
474	  // Finished spawn → emit end event and close the stream. No tail, no keepalive.
475	  if (isFinished) {
476	    const endPayload = JSON.stringify({
477	      status: entry.status,
478	      endedAt: entry.endedAt || null,
479	    });
480	    try { res.write("event: end\ndata: " + endPayload + "\n\n"); } catch { /* gone */ }
481	    try { res.end(); } catch { /* gone */ }
482	    return;
483	  }
484	
485	  // Missing file — tell the viewer the stream is live but empty. fs.watchFile
486	  // needs the file to exist, so we skip the tail here. A running producer
487	  // will have created the file already (the finished-spawn branch above
488	  // catches the post-hoc teed case via index status).
489	  if (!exists) {
490	    const waitingPayload = JSON.stringify({
491	      status: "waiting",
492	      reason: "no transcript file yet",
493	    });
494	    try { res.write("event: status\ndata: " + waitingPayload + "\n\n"); } catch { /* gone */ }
495	    const timer = setInterval(() => { try { res.write(": keepalive\n\n"); } catch { clearInterval(timer); } }, KEEPALIVE_MS);
496	    req.on("close", () => { clearInterval(timer); });
497	    return;
498	  }
499	
500	  // Empty file — producer hasn't written anything yet. Emit a status frame
501	  // so the viewer knows the stream is live but the file is 0 bytes, then
502	  // attach the live tail so we pick up writes as they arrive.
503	  if (fileSize === 0) {
504	    const emptyPayload = JSON.stringify({
505	      status: "empty",
506	      reason: "transcript file exists but is empty",
507	    });
508	    try { res.write("event: status\ndata: " + emptyPayload + "\n\n"); } catch { /* gone */ }
509	  }
510	
511	  // Tail: from replayedBytes onward. We reuse the tailer, but seed offset
512	  // with what we already replayed so we don't double-send.
513	  let offset = replayedBytes;
514	  let buf = "";
515	  const processNewData = () => {
516	    let stat;
517	    try { stat = fs.statSync(filePath); } catch { return; }
518	    if (stat.size <= offset) return;
519	    const fd = fs.openSync(filePath, "r");
520	    try {
521	      const b = Buffer.alloc(stat.size - offset);
522	      fs.readSync(fd, b, 0, b.length, offset);
523	      buf += b.toString("utf8");
524	      offset = stat.size;
525	    } finally { fs.closeSync(fd); }
526	    let nl;
527	    while ((nl = buf.indexOf("\n")) >= 0) {
528	      const line = buf.slice(0, nl);
529	      buf = buf.slice(nl + 1);
530	      if (line.length > 0) {
531	        try { res.write("data: " + line + "\n\n"); } catch { /* gone */ }
532	      }
533	    }
534	  };
535	  fs.watchFile(filePath, { interval: 500, persistent: true }, processNewData);
536	  const unwatchFile = () => fs.unwatchFile(filePath, processNewData);
537	
538	  const timer = setInterval(() => { try { res.write(": keepalive\n\n"); } catch { clearInterval(timer); } }, KEEPALIVE_MS);
539	  req.on("close", () => { clearInterval(timer); if (unwatchFile) unwatchFile(); });
540	}
541	
542	// ── M44 D8 — spawn-plan endpoint + SSE channel ─────────────────────────────
543	//
544	// Additive; does not change existing endpoints or SSE streams. Reads plan
545	// files atomically written by `bin/spawn-plan-writer.cjs` under
546	// `.gsd-t/spawns/{spawnId}.json`. A plan is "active" when `endedAt === null`.
547	// Contract: .gsd-t/contracts/spawn-plan-contract.md v1.0.0
548	
549	const SPAWNS_SUBDIR = path.join(".gsd-t", "spawns");
550	
551	function spawnsDir(projectDir) {
552	  return path.join(projectDir, SPAWNS_SUBDIR);
553	}
554	
555	function readSpawnPlanFile(fp) {
556	  try {
557	    const raw = fs.readFileSync(fp, "utf8");
558	    const parsed = JSON.parse(raw);
559	    if (!parsed || typeof parsed !== "object") return null;
560	    return parsed;
561	  } catch { return null; }
562	}
563	
564	function listAllSpawnPlans(projectDir) {
565	  const dir = spawnsDir(projectDir);
566	  if (!fs.existsSync(dir)) return [];
567	  let files;
568	  try { files = fs.readdirSync(dir).filter((f) => f.endsWith(".json")); } catch { return []; }
569	  const out = [];
570	  for (const f of files) {
571	    const plan = readSpawnPlanFile(path.join(dir, f));
572	    if (plan) out.push(plan);
573	  }
574	  return out;
575	}
576	
577	function listActiveSpawnPlans(projectDir) {
578	  return listAllSpawnPlans(projectDir).filter((p) => p && p.endedAt == null);
579	}
