581	function handleSpawnPlans(req, res, projectDir) {
582	  const plans = listActiveSpawnPlans(projectDir).sort((a, b) => {
583	    const ta = Date.parse(a.startedAt) || 0;
584	    const tb = Date.parse(b.startedAt) || 0;
585	    return tb - ta;
586	  });
587	  res.writeHead(200, { "Content-Type": "application/json", "Access-Control-Allow-Origin": "*" });
588	  res.end(JSON.stringify({ plans, generated_at: new Date().toISOString() }));
589	}
590	
591	function handleSpawnPlanUpdates(req, res, projectDir) {
592	  res.writeHead(200, SSE_HEADERS);
593	  // Initial snapshot: every current active plan.
594	  const initial = listActiveSpawnPlans(projectDir);
595	  for (const plan of initial) {
596	    try { res.write("data: " + JSON.stringify({ spawnId: plan.spawnId, plan }) + "\n\n"); } catch { /* gone */ }
597	  }
598	
599	  const dir = spawnsDir(projectDir);
600	  let dirWatcher = null;
601	  const emittedCache = new Map(); // spawnId → last-mtime-ms, dedup rapid rename events
602	
603	  function pushChange(spawnId) {
604	    if (!spawnId) return;
605	    const fp = path.join(dir, spawnId + ".json");
606	    let mtime = 0;
607	    try { mtime = fs.statSync(fp).mtimeMs || 0; } catch { /* missing */ }
608	    // Dedup rapid-fire rename events — only emit when mtime advances.
609	    if (emittedCache.get(spawnId) === mtime && mtime > 0) return;
610	    emittedCache.set(spawnId, mtime);
611	    const plan = readSpawnPlanFile(fp);
612	    if (!plan) return;
613	    try { res.write("data: " + JSON.stringify({ spawnId, plan }) + "\n\n"); } catch { /* gone */ }
614	  }
615	
616	  try {
617	    if (fs.existsSync(dir)) {
618	      dirWatcher = fs.watch(dir, (eventType, filename) => {
619	        if (!filename || !filename.endsWith(".json")) return;
620	        const spawnId = filename.slice(0, -5);
621	        pushChange(spawnId);
622	      });
623	    }
624	  } catch { /* dir may not exist yet; skip watch */ }
625	
626	  const timer = setInterval(() => { try { res.write(": keepalive\n\n"); } catch { clearInterval(timer); } }, KEEPALIVE_MS);
627	  req.on("close", () => { clearInterval(timer); if (dirWatcher) { try { dirWatcher.close(); } catch { /* ok */ } } });
628	}
