630	function startServer(port, eventsDir, htmlPath, projectDir, transcriptHtmlPath) {
631	  const projDir = projectDir || path.resolve(eventsDir, "..", "..");
632	  const tHtmlPath = transcriptHtmlPath || path.join(path.dirname(htmlPath), "gsd-t-transcript.html");
633	  const server = http.createServer((req, res) => {
634	    const url = req.url.split("?")[0];
635	    if (url === "/" || url === "") return handleRoot(req, res, htmlPath);
636	    if (url === "/events") return handleEvents(req, res, eventsDir);
637	    if (url === "/metrics") return handleMetrics(req, res, projDir);
638	    if (url === "/ping") return handlePing(req, res, port);
639	    if (url === "/stop") return handleStop(req, res, server);
640	    if (url === "/transcripts") return handleTranscriptsList(req, res, projDir);
641	    // M44 D8 — spawn plans: GET list + SSE change stream
642	    if (url === "/api/spawn-plans") return handleSpawnPlans(req, res, projDir);
643	    if (url === "/api/spawn-plans/stream") return handleSpawnPlanUpdates(req, res, projDir);
644	    // POST /transcript/:spawnId/kill — SIGTERM the recorded workerPid
645	    const killMatch = url.match(/^\/transcript\/([^/]+)\/kill$/);
646	    if (killMatch && req.method === "POST") return handleTranscriptKill(req, res, decodeURIComponent(killMatch[1]), projDir);
647	    // M43 D6 — /transcript/:spawnId/tool-cost — D2 attribution proxy
648	    const toolCostMatch = url.match(/^\/transcript\/([^/]+)\/tool-cost$/);
649	    if (toolCostMatch) return handleTranscriptToolCost(req, res, decodeURIComponent(toolCostMatch[1]), projDir);
650	    // M43 D6 — /transcript/:spawnId/usage — per-turn rows for this spawn
651	    const usageMatch = url.match(/^\/transcript\/([^/]+)\/usage$/);
652	    if (usageMatch) return handleTranscriptUsage(req, res, decodeURIComponent(usageMatch[1]), projDir);
653	    // /transcript/:spawnId/stream — SSE tail of per-spawn ndjson
654	    const streamMatch = url.match(/^\/transcript\/([^/]+)\/stream$/);
655	    if (streamMatch) return handleTranscriptStream(req, res, decodeURIComponent(streamMatch[1]), projDir);
656	    // /transcript/:spawnId — HTML viewer page
657	    const pageMatch = url.match(/^\/transcript\/([^/]+)$/);
658	    if (pageMatch) return handleTranscriptPage(req, res, decodeURIComponent(pageMatch[1]), tHtmlPath);
659	    res.writeHead(404); res.end("Not found");
660	  });
661	  server.listen(port);
662	  return { server, url: `http://localhost:${port}` };
663	}
