697	if (require.main === module) {
698	  const argv = process.argv.slice(2);
699	  const getArg = (flag) => { const i = argv.indexOf(flag); return i >= 0 ? argv[i + 1] : null; };
700	  const hasFlag = (f) => argv.includes(f);
701	  const projectDir = process.env.GSD_T_PROJECT_DIR || process.cwd();
702	  const port = resolvePort({ argPort: getArg("--port"), projectDir });
703	  const eventsDir = getArg("--events") || findEventsDir(projectDir);
