708	  if (hasFlag("--stop")) {
709	    try { const pid = parseInt(fs.readFileSync(pidFile, "utf8").trim(), 10); process.kill(pid); fs.unlinkSync(pidFile); }
710	    catch (e) { process.stderr.write("No running server: " + e.message + "\n"); }
711	    process.exit(0);
712	  }
713	  if (hasFlag("--detach")) {
714	    const child = spawn(process.execPath, [__filename, ...argv.filter((a) => a !== "--detach")], { detached: true, stdio: "ignore" });
715	    child.unref();
716	    try { fs.mkdirSync(path.dirname(pidFile), { recursive: true }); } catch { /* exists */ }
717	    fs.writeFileSync(pidFile, String(child.pid));
718	    process.exit(0);
719	  }
720	  const { server, url } = startServer(port, eventsDir, htmlPath, projectDir, transcriptHtmlPath);
721	  process.stdout.write("GSD-T Dashboard: " + url + "\n");
722	  function cleanup() { try { fs.unlinkSync(pidFile); } catch { /* ok */ } server.close(() => process.exit(0)); }
723	  process.on("SIGTERM", cleanup);
724	  process.on("SIGINT", cleanup);
725	}
