1	#!/usr/bin/env node
2	'use strict';
3	/**
4	 * GSD-T In-Session Usage Hook (M43 D1-T2)
5	 *
6	 * Installed into `~/.claude/settings.json` (Stop + SessionEnd) to capture
7	 * per-turn token usage for the dialog channel. Reads the hook payload from
8	 * stdin, resolves the project directory from `payload.cwd`, then delegates to
9	 * `bin/gsd-t-in-session-usage.cjs::processHookPayload` which reads the
10	 * transcript at `payload.transcript_path` and appends schema-v2 rows to
11	 * `.gsd-t/metrics/token-usage.jsonl`.
12	 *
13	 * Silent on success (hooks run async in Claude Code — stdout is ignored).
14	 * Swallows every error: a flaky capture must never break the user's session.
15	 */
16	
17	const fs = require('fs');
18	const path = require('path');
19	
20	const DEFAULT_SCRIPT_GUARD_MS = 5000;
21	const started = Date.now();
22	
23	function _readStdin() {
24	  return new Promise((resolve) => {
25	    let buf = '';
26	    process.stdin.setEncoding('utf8');
27	    process.stdin.on('data', chunk => { buf += chunk; });
28	    process.stdin.on('end', () => resolve(buf));
29	    process.stdin.on('error', () => resolve(buf));
30	    setTimeout(() => resolve(buf), DEFAULT_SCRIPT_GUARD_MS).unref();
31	  });
32	}
33	
34	function _parsePayload(raw) {
35	  try {
36	    return JSON.parse(raw || '{}');
37	  } catch (_) {
38	    return null;
39	  }
40	}
41	
42	function _resolveProjectDir(payload) {
43	  if (payload && payload.cwd && fs.existsSync(payload.cwd)) return payload.cwd;
44	  if (process.cwd) return process.cwd();
45	  return '.';
46	}
47	
48	function _resolveInSessionModule(projectDir) {
49	  const candidates = [
50	    path.join(projectDir, 'bin', 'gsd-t-in-session-usage.cjs'),
51	    path.join(process.env.HOME || '', '.claude', 'gsd-t', 'bin', 'gsd-t-in-session-usage.cjs'),
52	  ];
53	  for (const p of candidates) {
54	    if (fs.existsSync(p)) return p;
55	  }
56	  return null;
57	}
58	
59	async function main() {
60	  try {
61	    const raw = await _readStdin();
62	    const payload = _parsePayload(raw);
63	    if (!payload) return;
64	    if (payload.hook_event_name !== 'Stop' && payload.hook_event_name !== 'SessionEnd') return;
65	
