2	/**
3	 * gsd-t-compact-detector.js
4	 *
5	 * SessionStart hook that records compaction events.
6	 *
7	 * Claude Code fires SessionStart with `source: "compact"` immediately after an
8	 * auto-compaction. By contrast, a fresh launch fires with `source: "startup"`
9	 * and a resumed session fires with `source: "resume"`. Only `compact` is
10	 * recorded — it's the transition marker that separates one Context Window
11	 * from the next.
12	 *
13	 * Without this hook, Context Window boundaries are invisible: every iter
14	 * silently looks like a single CW. That breaks the canonical measurement
15	 * hierarchy (Run → Iter → Context Window → Turn → Tool call).
16	 *
17	 * Behavior:
18	 * - Zero-dep. Reads stdin JSON, silently fails on any error. Always exits 0 —
19	 *   throwing here would break Claude Code session startup.
20	 * - Only acts when `source === "compact"`.
21	 * - Appends one NDJSON row to `<cwd>/.gsd-t/metrics/compactions.jsonl`.
22	 * - Appends one compact_marker frame to the most-recently-modified
23	 *   `<cwd>/.gsd-t/transcripts/*.ndjson` (the live transcript). No-ops
24	 *   silently when no transcript exists.
25	 * - 1 MiB stdin cap (defense in depth; real payloads are tiny).
26	 * - Path-traversal guard: refuses any cwd that doesn't let the resolved
27	 *   output path stay under `<cwd>/.gsd-t/metrics/`.
28	 * - Off switch: if `<cwd>/.gsd-t/` does not exist, silent no-op. Creating it
29	 *   is opt-in; deleting it disables the hook without having to edit
30	 *   settings.json.
31	 *
32	 * Contract: .gsd-t/contracts/compaction-events-contract.md
33	 */
34	"use strict";
35	
36	const fs = require("fs");
37	const path = require("path");
38	
39	const MAX_STDIN = 1024 * 1024; // 1 MiB
40	const SCHEMA_VERSION = 1;
41	
42	let input = "";
43	let aborted = false;
44	
45	process.stdin.setEncoding("utf8");
46	process.stdin.on("data", (chunk) => {
47	  input += chunk;
48	  if (input.length > MAX_STDIN) {
49	    aborted = true;
50	    try { process.stdin.destroy(); } catch { /* noop */ }
51	  }
52	});
53	process.stdin.on("error", () => { /* silent */ });
54	process.stdin.on("end", () => {
55	  if (aborted) { exitClean(); return; }
56	  let payload;
57	  try {
58	    payload = JSON.parse(input);
59	  } catch {
60	    exitClean();
61	    return;
62	  }
63	
64	  if (!payload || typeof payload !== "object") { exitClean(); return; }
65	
66	  // Only record `compact`. Startup / resume are no-ops.
67	  if (payload.source !== "compact") { exitClean(); return; }
68	
69	  try {
70	    writeRow(payload);
71	  } catch {
72	    // silent — never throw
73	  }
74	  try {
75	    writeTranscriptMarker(payload);
76	  } catch {
77	    // silent — never throw
78	  }
79	  exitClean();
80	});
81	
82	function writeRow(payload) {
83	  // `cwd` must be absolute when present. An invalid value is NOT silently
84	  // coerced to process.cwd() — that would let a malformed payload write
85	  // into whatever dir the hook happened to be spawned from.
86	  let cwd;
87	  if (typeof payload.cwd === "string") {
88	    if (!path.isAbsolute(payload.cwd)) return; // invalid — no-op
89	    cwd = payload.cwd;
90	  } else if (payload.cwd === undefined || payload.cwd === null) {
91	    cwd = process.cwd();
92	  } else {
93	    return; // non-string cwd — no-op
94	  }
95	
96	  // `.gsd-t/` must exist — acts as the off-switch.
97	  const gsdDir = path.join(cwd, ".gsd-t");
98	  if (!fs.existsSync(gsdDir)) return;
99	
100	  const metricsDir = path.join(gsdDir, "metrics");
101	  const outPath = path.join(metricsDir, "compactions.jsonl");
102	
103	  // Path-traversal guard.
104	  const resolvedOut = path.resolve(outPath);
105	  const resolvedMetrics = path.resolve(metricsDir) + path.sep;
106	  if (!resolvedOut.startsWith(resolvedMetrics)) return;
107	
108	  try {
109	    fs.mkdirSync(metricsDir, { recursive: true });
110	  } catch {
111	    return;
112	  }
113	
114	  const row = {
115	    ts: new Date().toISOString(),
116	    schemaVersion: SCHEMA_VERSION,
117	    session_id: typeof payload.session_id === "string" ? payload.session_id : null,
118	    prior_session_id: typeof payload.prior_session_id === "string"
119	      ? payload.prior_session_id
120	      : (typeof payload.previous_session_id === "string"
121	          ? payload.previous_session_id
122	          : null),
123	    source: "compact",
124	    cwd,
125	    hook: "SessionStart",
126	  };
127	
128	  fs.appendFileSync(outPath, JSON.stringify(row) + "\n", "utf8");
129	}
130	
131	/**
132	 * Find the most-recently-modified .ndjson in <cwd>/.gsd-t/transcripts/.
133	 * Returns the absolute path, or null if none exists or the directory is absent.
134	 */
135	function findActiveTranscript(cwd) {
136	  const transcriptsDir = path.join(cwd, ".gsd-t", "transcripts");
137	  let entries;
138	  try {
139	    entries = fs.readdirSync(transcriptsDir);
140	  } catch {
141	    return null;
142	  }
143	  const ndjsons = entries.filter((e) => e.endsWith(".ndjson"));
144	  if (!ndjsons.length) return null;
145	
146	  let newest = null;
147	  let newestMtime = -1;
148	  for (const name of ndjsons) {
149	    const full = path.join(transcriptsDir, name);
150	    try {
151	      const stat = fs.statSync(full);
152	      if (stat.mtimeMs > newestMtime) {
153	        newestMtime = stat.mtimeMs;
154	        newest = full;
155	      }
156	    } catch {
157	      // skip unreadable entries
158	    }
159	  }
160	  return newest;
161	}
162	
163	/**
164	 * Append a compact_marker frame to the active transcript NDJSON.
165	 * No-ops silently when no transcript exists.
166	 */
167	function writeTranscriptMarker(payload) {
168	  let cwd;
169	  if (typeof payload.cwd === "string") {
170	    if (!path.isAbsolute(payload.cwd)) return;
171	    cwd = payload.cwd;
172	  } else if (payload.cwd === undefined || payload.cwd === null) {
173	    cwd = process.cwd();
174	  } else {
175	    return;
176	  }
177	
178	  const gsdDir = path.join(cwd, ".gsd-t");
179	  if (!fs.existsSync(gsdDir)) return;
180	
181	  const transcriptPath = findActiveTranscript(cwd);
182	  if (!transcriptPath) return;
183	
184	  // Path-traversal guard: resolved transcript path must stay under <cwd>/.gsd-t/transcripts/
185	  const transcriptsDir = path.join(gsdDir, "transcripts") + path.sep;
186	  if (!path.resolve(transcriptPath).startsWith(path.resolve(transcriptsDir))) return;
187	
188	  const marker = {
189	    type: "compact_marker",
190	    ts: new Date().toISOString(),
191	    source: "compact",
192	    session_id: typeof payload.session_id === "string" ? payload.session_id : null,
193	    prior_session_id: typeof payload.prior_session_id === "string"
194	      ? payload.prior_session_id
195	      : (typeof payload.previous_session_id === "string"
196	          ? payload.previous_session_id
197	          : null),
198	  };
199	
200	  // Include optional fields when present.
201	  if (typeof payload.trigger === "string") marker.trigger = payload.trigger;
202	  if (typeof payload.preTokens === "number") marker.preTokens = payload.preTokens;
203	  if (typeof payload.postTokens === "number") marker.postTokens = payload.postTokens;
204	  // Also check nested compactMetadata (scanner shape).
205	  if (payload.compactMetadata && typeof payload.compactMetadata === "object") {
206	    if (typeof payload.compactMetadata.trigger === "string" && !marker.trigger) {
207	      marker.trigger = payload.compactMetadata.trigger;
208	    }
209	    if (typeof payload.compactMetadata.preTokens === "number" && marker.preTokens == null) {
210	      marker.preTokens = payload.compactMetadata.preTokens;
211	    }
212	    if (typeof payload.compactMetadata.postTokens === "number" && marker.postTokens == null) {
213	      marker.postTokens = payload.compactMetadata.postTokens;
214	    }
215	  }
216	
217	  fs.appendFileSync(transcriptPath, JSON.stringify(marker) + "\n", "utf8");
218	}
219	
220	function exitClean() {
221	  try { process.stdout.write(""); } catch { /* noop */ }
222	  process.exit(0);
223	}
