4	 * GSD-T Conversation Capture Hook (M45 D2)
5	 *
6	 * Captures the orchestrator session's conversational turns into
7	 * `.gsd-t/transcripts/in-session-{sessionId}.ndjson` so the visualizer
8	 * left rail can list the in-session conversation alongside spawn entries.
9	 *
10	 * Installed into `~/.claude/settings.json` (SessionStart, UserPromptSubmit,
11	 * Stop, optional PostToolUse). Reads the hook payload from stdin, dispatches
12	 * on `hook_event_name`, appends a typed NDJSON frame. Writes content-level
13	 * data (not just tokens — that's the job of `gsd-t-in-session-usage-hook.js`).
14	 *
15	 * Safety:
16	 * - Never throws to the caller — catches all errors, logs to stderr, exits 0.
17	 * - `content` is capped at 16 KB per frame; over-cap writes `truncated: true`.
18	 * - Append-only; never overwrites an existing in-session NDJSON file.
19	 * - Project-dir discovery: prefers `GSD_T_PROJECT_DIR`, then `payload.cwd`,
20	 *   then walks up from `process.cwd()` looking for `.gsd-t/progress.md`.
21	 *   Silent no-op if no project dir found.
22	 *
23	 * Contract: .gsd-t/contracts/conversation-capture-contract.md v1.0.0
24	 */
25	
26	const fs = require('fs');
27	const path = require('path');
28	const crypto = require('crypto');
29	
30	const DEFAULT_SCRIPT_GUARD_MS = 5000;
31	const CONTENT_CAP_BYTES = 16 * 1024; // 16 KB
32	const MAX_STDIN = 1024 * 1024; // 1 MiB defense-in-depth
33	const started = Date.now();
34	
35	function _readStdin() {
36	  return new Promise((resolve) => {
37	    let buf = '';
38	    let aborted = false;
39	    process.stdin.setEncoding('utf8');
40	    process.stdin.on('data', (chunk) => {
41	      if (aborted) return;
42	      buf += chunk;
43	      if (buf.length > MAX_STDIN) {
44	        aborted = true;
45	        try { process.stdin.destroy(); } catch (_) { /* noop */ }
46	        resolve('');
47	      }
48	    });
49	    process.stdin.on('end', () => { if (!aborted) resolve(buf); });
50	    process.stdin.on('error', () => resolve(buf));
51	    setTimeout(() => resolve(buf), DEFAULT_SCRIPT_GUARD_MS).unref();
52	  });
53	}
54	
55	function _parsePayload(raw) {
56	  try { return JSON.parse(raw || '{}'); } catch (_) { return null; }
57	}
58	
59	function _walkUpForProject(startDir) {
60	  try {
61	    let dir = path.resolve(startDir || '.');
62	    for (let i = 0; i < 10; i++) {
63	      if (fs.existsSync(path.join(dir, '.gsd-t', 'progress.md'))) return dir;
64	      const parent = path.dirname(dir);
65	      if (parent === dir) break;
66	      dir = parent;
67	    }
68	  } catch (_) { /* swallow */ }
69	  return null;
70	}
71	
72	function _resolveProjectDir(payload) {
73	  const env = process.env.GSD_T_PROJECT_DIR;
74	  if (env && fs.existsSync(path.join(env, '.gsd-t'))) return env;
75	  if (payload && typeof payload.cwd === 'string' && path.isAbsolute(payload.cwd)
76	      && fs.existsSync(path.join(payload.cwd, '.gsd-t'))) {
77	    return payload.cwd;
78	  }
79	  const walked = _walkUpForProject(process.cwd());
80	  if (walked) return walked;
81	  return null;
82	}
83	
84	function _resolveSessionId(payload) {
85	  if (payload && typeof payload.session_id === 'string' && payload.session_id.length > 0) {
86	    return payload.session_id;
87	  }
88	  // Fallback: deterministic-ish per-process hash. Stable within one process,
89	  // different across processes. Keeps the filename non-empty when Claude Code
90	  // omits session_id (shouldn't happen in practice but we must not explode).
91	  const seed = String(process.pid) + ':' + String(started);
92	  return 'pid-' + crypto.createHash('sha1').update(seed).digest('hex').slice(0, 12);
93	}
94	
95	function _capContent(raw) {
96	  if (raw == null) return { content: null, truncated: false };
97	  let str;
98	  if (typeof raw === 'string') str = raw;
99	  else {
100	    try { str = JSON.stringify(raw); } catch (_) { str = String(raw); }
101	  }
102	  const byteLen = Buffer.byteLength(str, 'utf8');
103	  if (byteLen <= CONTENT_CAP_BYTES) return { content: str, truncated: false };
104	  // Truncate by bytes; slice then re-decode to avoid breaking a multi-byte char.
105	  const buf = Buffer.from(str, 'utf8').subarray(0, CONTENT_CAP_BYTES);
106	  return { content: buf.toString('utf8'), truncated: true };
107	}
