114	  const resolvedOut = path.resolve(outPath);
115	  const resolvedDir = path.resolve(transcriptsDir) + path.sep;
116	  if (!resolvedOut.startsWith(resolvedDir)) return;
117	  fs.appendFileSync(outPath, JSON.stringify(frame) + '\n', 'utf8');
118	}
119	
120	function _extractUserContent(payload) {
121	  // Claude Code UserPromptSubmit payload carries the prompt text.
122	  if (payload && typeof payload.prompt === 'string') return payload.prompt;
123	  if (payload && payload.message && typeof payload.message.content === 'string') {
124	    return payload.message.content;
125	  }
126	  if (payload && payload.user_message && typeof payload.user_message === 'string') {
127	    return payload.user_message;
128	  }
129	  return null;
130	}
131	
132	function _extractAssistantContent(payload) {
