134	  // still emit a stub frame (ts + session_id only).
135	  if (payload && typeof payload.assistant_message === 'string') return payload.assistant_message;
136	  if (payload && payload.message && typeof payload.message.content === 'string') {
137	    return payload.message.content;
138	  }
139	  if (payload && typeof payload.content === 'string') return payload.content;
140	  return null;
141	}
