143	function _buildUserFrame(payload, sessionId, ts) {
144	  const { content, truncated } = _capContent(_extractUserContent(payload));
145	  const frame = {
146	    type: 'user_turn',
147	    ts,
148	    session_id: sessionId,
149	  };
150	  if (content != null) frame.content = content;
