152	  if (payload && typeof payload.message_id === 'string') frame.message_id = payload.message_id;
153	  return frame;
154	}
155	
156	function _buildAssistantFrame(payload, sessionId, ts) {
157	  const { content, truncated } = _capContent(_extractAssistantContent(payload));
158	  const frame = {
