177	    session_id: sessionId,
178	  };
179	  if (payload && typeof payload.tool_name === 'string') frame.name = payload.tool_name;
180	  else if (payload && payload.tool && typeof payload.tool.name === 'string') frame.name = payload.tool.name;
181	  if (payload && typeof payload.tool_use_id === 'string') frame.tool_use_id = payload.tool_use_id;
182	  if (payload && typeof payload.duration_ms === 'number') frame.duration_ms = payload.duration_ms;
183	  return frame;
184	}
185	
186	function _handle(payload) {
187	  if (!payload || typeof payload !== 'object') return;
188	  const event = payload.hook_event_name;
189	  if (!event) return;
190	
191	  const projectDir = _resolveProjectDir(payload);
192	  if (!projectDir) return; // not a GSD-T project — silent no-op
193	
194	  const sessionId = _resolveSessionId(payload);
195	  const ts = new Date().toISOString();
196	
197	  switch (event) {
198	    case 'SessionStart': {
199	      _appendFrame(projectDir, sessionId, _buildSessionStartFrame(sessionId, ts));
200	      return;
201	    }
202	    case 'UserPromptSubmit': {
203	      _appendFrame(projectDir, sessionId, _buildUserFrame(payload, sessionId, ts));
204	      return;
205	    }
206	    case 'Stop': {
207	      _appendFrame(projectDir, sessionId, _buildAssistantFrame(payload, sessionId, ts));
208	      return;
209	    }
210	    case 'PostToolUse': {
211	      // Opt-in: guarded to keep default writes small.
212	      if (process.env.GSD_T_CAPTURE_TOOL_USES !== '1') return;
213	      _appendFrame(projectDir, sessionId, _buildToolUseFrame(payload, sessionId, ts));
214	      return;
215	    }
216	    default:
217	      return;
218	  }
219	}
220	
221	async function main() {
222	  try {
223	    const raw = await _readStdin();
224	    const payload = _parsePayload(raw);
225	    if (!payload) return;
226	    _handle(payload);
227	  } catch (err) {
228	    try { process.stderr.write('gsd-t-conversation-capture: ' + (err && err.message || err) + '\n'); } catch (_) { /* noop */ }
229	  } finally {
230	    const elapsed = Date.now() - started;
231	    if (elapsed > DEFAULT_SCRIPT_GUARD_MS) process.exitCode = 0;
232	  }
233	}
234	
235	if (require.main === module) {
236	  main();
237	}
238	
239	module.exports = {
240	  _internal: {
241	    _parsePayload,
