+      continue;
+    }
+    const isInSession = name.indexOf("in-session-") === 0;
+    if (isInSession) {
+      if (mtimeMs > newestInSessionMtime) {
+        newestInSessionMtime = mtimeMs;
+        newestInSession = full;
+      }
